def solve_scheduling(jobs, resources):
    '''
    RCPSP solver using Serial Schedule Generation Scheme with Priority Rules.
    Optimizes for Makespan minimization.
    '''
    # Build dictionaries for efficient access
    job_dict = {job['id']: job for job in jobs}
    resource_dict = {res['id']: res for res in resources}

    # Initialize scheduling state
    scheduled_jobs = {}
    resource_usage = {res['id']: {'used': 0, 'capacity': res['capacity']} for res in resources}
    current_time = 0
    makespan = 0
    completed_jobs = set()

    # Priority calculation using Most Total Successors (MTS) rule
    def calculate_priority(job_id):
        job = job_dict[job_id]
        successors = job.get('successors', [])
        # Weight by number of successors (MTS heuristic)
        return len(successors)

    # Find all available jobs (predecessors completed, not yet scheduled)
    def get_available_jobs():
        available = []
        for job_id, job in job_dict.items():
            if job_id not in completed_jobs:
                predecessors = job.get('predecessors', [])
                if all(pred in completed_jobs for pred in predecessors):
                    available.append(job_id)
        return available

    # Check if resources are available for a job at current time
    def can_schedule_resources(job_id):
        job = job_dict[job_id]
        mode = job['modes'][0]  # Single mode execution

        for res_id, amount in mode['resources_required'].items():
            if resource_dict[res_id]['capacity'] < amount:
                return False
        return True

    # Schedule jobs using Serial SGS with priority rules
    while len(completed_jobs) < len(jobs):
        available_jobs = get_available_jobs()

        if not available_jobs:
            break

        # Sort by priority (MTS rule - highest successors first)
        available_jobs.sort(key=lambda j: calculate_priority(j), reverse=True)

        scheduled_this_iteration = False

        for job_id in available_jobs:
            job = job_dict[job_id]
            mode = job['modes'][0]
            duration = mode['duration']

            # Check resource availability
            if can_schedule_resources(job_id):
                # Schedule the job
                scheduled_jobs[job_id] = {
                    'start_time': current_time,
                    'end_time': current_time + duration,
                    'mode': mode
                }

                # Update resource usage
                for res_id, amount in mode['resources_required'].items():
                    resource_usage[res_id]['used'] += amount

                # Mark job as completed
                completed_jobs.add(job_id)

                makespan = max(makespan, current_time + duration)
                scheduled_this_iteration = True
                break

        # If no job could be scheduled, advance time
        if not scheduled_this_iteration:
            current_time += 1

    return {
        'schedule': scheduled_jobs,
        'makespan': makespan,
        'resource_usage': resource_usage
    }

