import heapq
from collections import defaultdict

def solve_scheduling(jobs, resources):
    """
    RCMPSP Solver using Multi-Priority Rule Heuristic

    Args:
        jobs: list of project dictionaries with activities and constraints
        resources: list of resource dictionaries with capacities

    Returns:
        dict: Schedule with start times, makespan, and resource usage
    """

    # Flatten all activities across projects
    all_activities = []
    activity_map = {}  # (project_id, activity_id) -> activity_info

    for project in jobs:
        project_id = project['project_id']
        for activity in project['activities']:
            act_id = activity['id']
            activity_map[(project_id, act_id)] = {
                'project_id': project_id,
                'activity_id': act_id,
                'duration': activity['duration'],
                'resources_required': activity['resources_required'],
                'successors': activity['successors'],
                'predecessors': [],
                'earliest_start': 0,
                'latest_start': float('inf'),
                'slack': float('inf'),
                'status': 'pending'  # pending, ready, in_progress, completed
            }
            all_activities.append(activity_map[(project_id, act_id)])

    # Build predecessor relationships
    for act in all_activities:
        for succ_id in act['successors']:
            # Find predecessor activity
            for other_act in all_activities:
                if other_act['activity_id'] == succ_id:
                    other_act['predecessors'].append(act['activity_id'])

    # Calculate resource capacities
    resource_capacities = {r['id']: r['capacity'] for r in resources}

    # Schedule construction
    schedule = []
    resource_usage = defaultdict(list)  # time -> {resource_id: used_amount}
    completed_activities = set()
    current_time = 0

    def get_ready_activities():
        """Get activities that are ready to be scheduled"""
        ready = []
        for act in all_activities:
            if act['status'] == 'pending':
                # Check if all predecessors are completed
                if all(pred in completed_activities for pred in act['predecessors']):
                    ready.append(act)
        return ready

    def calculate_slack(activity):
        """Calculate slack time for an activity"""
        if activity['project_id'] not in [p['project_id'] for p in jobs]:
            return float('inf')

        project = next(p for p in jobs if p['project_id'] == activity['project_id'])
        due_date = project.get('due_date', float('inf'))

        # Calculate earliest finish time
        est = activity['earliest_start'] + activity['duration']
        return due_date - est

    def calculate_resource_priority(activity):
        """Calculate priority based on resource consumption"""
        total_resources = sum(activity['resources_required'])
        return total_resources

    def calculate_duration_priority(activity):
        """Calculate priority based on duration (LPT)"""
        return -activity['duration']  # Negative for min-heap

    def can_schedule_activity(activity, start_time):
        """Check if activity can be scheduled at given time"""
        for resource_idx, amount in enumerate(activity['resources_required']):
            if amount > 0:
                resource_id = resource_idx
                for t in range(start_time, start_time + activity['duration']):
                    if resource_id in resource_usage[t]:
                        if resource_usage[t][resource_id] + amount > resource_capacities[resource_id]:
                            return False
        return True

    def schedule_activity(activity, start_time):
        """Schedule an activity and update resource usage"""
        for t in range(start_time, start_time + activity['duration']):
            for resource_idx, amount in enumerate(activity['resources_required']):
                if amount > 0:
                    resource_id = resource_idx
                    if resource_id not in resource_usage[t]:
                        resource_usage[t][resource_id] = 0
                    resource_usage[t][resource_id] += amount

        activity['status'] = 'completed'
        activity['start_time'] = start_time
        activity['finish_time'] = start_time + activity['duration']
        schedule.append({
            'project_id': activity['project_id'],
            'activity_id': activity['activity_id'],
            'start_time': start_time,
            'finish_time': activity['finish_time'],
            'duration': activity['duration']
        })
        completed_activities.add(activity['activity_id'])

    # Main scheduling loop
    while len(completed_activities) < len(all_activities):
        ready = get_ready_activities()

        if not ready:
            # No ready activities, advance time
            if resource_usage:
                current_time = max(resource_usage.keys()) + 1
            else:
                current_time += 1
            continue

        # Calculate priorities for ready activities
        priority_scores = []
        for act in ready:
            slack = calculate_slack(act)
            resource_priority = calculate_resource_priority(act)
            duration_priority = calculate_duration_priority(act)

            # Multi-criteria priority (weighted combination)
            # Higher slack = lower priority, more resources = higher priority
            priority_score = (slack * 0.4) + (resource_priority * 0.4) + (duration_priority * 0.2)
            priority_scores.append((priority_score, act))

        # Sort by priority score
        priority_scores.sort(key=lambda x: x[0])

        # Try to schedule highest priority activities
        scheduled_any = False
        for _, act in priority_scores:
            if can_schedule_activity(act, current_time):
                schedule_activity(act, current_time)
                scheduled_any = True
                break

        if not scheduled_any:
            current_time += 1

    # Calculate makespan
    makespan = max(s['finish_time'] for s in schedule) if schedule else 0

    return {
        'schedule': schedule,
        'makespan': makespan,
        'resource_usage': dict(resource_usage),
        'completed_activities': len(completed_activities)
    }
